<?php
declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('lecturer');$page_title='Grades - SMIS';$lecturer=db_one('SELECT * FROM lecturers WHERE user_id=:id',['id'=>current_user()['id']]);$assignment_id=(int)query('assignment');$assignments=db_all('SELECT lm.id,m.code,c.name class_name FROM lecturer_modules lm JOIN modules m ON m.id=lm.module_id JOIN classes c ON c.id=lm.class_id WHERE lm.lecturer_id=:id ORDER BY m.code',['id'=>$lecturer['id']]);$assignment=$assignment_id?db_one('SELECT lm.*,m.code,m.title,c.name class_name FROM lecturer_modules lm JOIN modules m ON m.id=lm.module_id JOIN classes c ON c.id=lm.class_id WHERE lm.id=:id AND lm.lecturer_id=:lecturer',['id'=>$assignment_id,'lecturer'=>$lecturer['id']]):null;
if(is_post()&&$assignment){enforce_csrf();foreach((array)post('coursework',[]) as $student=>$cw){$cw=max(0,min(30,(float)$cw));$exam=max(0,min(70,(float)post('examination_'.$student)));$final=$cw+$exam;db_execute('INSERT INTO grades(student_id,module_id,lecturer_id,coursework,examination,final_grade,letter_grade,remarks) VALUES(:student,:module,:lecturer,:cw,:exam,:final,:letter,:remarks) ON DUPLICATE KEY UPDATE coursework=VALUES(coursework),examination=VALUES(examination),final_grade=VALUES(final_grade),letter_grade=VALUES(letter_grade),remarks=VALUES(remarks),lecturer_id=VALUES(lecturer_id)',['student'=>(int)$student,'module'=>$assignment['module_id'],'lecturer'=>$lecturer['id'],'cw'=>$cw,'exam'=>$exam,'final'=>$final,'letter'=>letter_grade($final),'remarks'=>(string)post('remarks_'.$student)]);}audit_log('upload_grades','modules',(string)$assignment['module_id']);respond_success('Marks saved and final grades calculated.','lecturer/grades.php?assignment='.$assignment_id);}
$students=$assignment?db_all('SELECT s.id,s.student_number,u.name,g.coursework,g.examination,g.final_grade,g.letter_grade,g.remarks FROM students s JOIN users u ON u.id=s.user_id JOIN student_modules sm ON sm.student_id=s.id AND sm.module_id=:module AND sm.semester_id=:semester LEFT JOIN grades g ON g.student_id=s.id AND g.module_id=:grade_module WHERE s.class_id=:class ORDER BY u.name',['module'=>$assignment['module_id'],'semester'=>$assignment['semester_id'],'grade_module'=>$assignment['module_id'],'class'=>$assignment['class_id']]):[];
include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Coursework & Examination Grades</h1><p>Coursework is marked out of 30 and examination out of 70. Final grade is calculated automatically.</p></div><div class="card"><div class="card-body"><form method="get"><label>Assignment</label><div class="hero-actions"><select class="form-control" name="assignment"><?php foreach($assignments as $a):?><option value="<?=$a['id']?>" <?=$assignment_id===$a['id']?'selected':''?>><?=e($a['class_name'].' · '.$a['code'])?></option><?php endforeach?></select><button class="btn btn-secondary">Load students</button></div></form></div></div>
<?php if($assignment):?><form method="post"><?=csrf_field()?><div class="card"><div class="card-header"><?=e($assignment['class_name'].' · '.$assignment['code'].' '.$assignment['title'])?></div><div class="card-body"><table class="table"><thead><tr><th>Student</th><th>Coursework /30</th><th>Examination /70</th><th>Final /100</th><th>Grade</th><th>Remarks</th></tr></thead><tbody><?php foreach($students as $s):?><tr><td><strong><?=e($s['name'])?></strong><br><small><?=e($s['student_number'])?></small></td><td><input class="form-control" type="number" step=".01" min="0" max="30" name="coursework[<?=$s['id']?>]" value="<?=e($s['coursework']??0)?>"></td><td><input class="form-control" type="number" step=".01" min="0" max="70" name="examination_<?=$s['id']?>" value="<?=e($s['examination']??0)?>"></td><td><strong><?=e($s['final_grade']??0)?></strong></td><td><?=e($s['letter_grade']??'-')?></td><td><input class="form-control" name="remarks_<?=$s['id']?>" value="<?=e($s['remarks']??'')?>"></td></tr><?php endforeach?></tbody></table><button class="btn btn-primary" style="margin-top:18px">Upload marks</button></div></div></form><?php endif?><?php include __DIR__.'/../includes/footer.php';?>
